1	// game-of-life.ts
2	export type Cell = [number, number];
3	
4	const isNeighbor = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
5	  Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1 && !(nx === x && ny === y);
6	
7	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
8	  const countLiveNeighbors = (cell: Cell): number =>
9	    liveCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	  return liveCells.filter((cell) => countLiveNeighbors(cell) === 3);
12	};
